class WorkspaceSearch{constructor(){this.index=null,this.documents=null,this.resultsContainer=document.getElementById("search-results"),this.searchInput=document.getElementById("search-input"),this.debounceTimer=null,this.init()}async init(){this.resultsContainer.innerHTML='\n      <div class="text-center p-8">\n        <div class="inline-block animate-spin rounded-full h-8 w-8 border-t-2 border-emerald-600"></div>\n        <p class="mt-2 text-gray-500">Loading search index…</p>\n      </div>\n    ';try{const e=await fetch("/search.json"),{index:t,documents:s}=await e.json();this.documents=s,this.index=lunr.Index.load(t),console.log("🔍 Search index loaded:",this.documents.length,"posts"),this.resultsContainer.classList.add("hidden"),this.showHint("Type at least 2 characters to search"),this.setupSearch()}catch(e){console.error("Failed to load search index:",e),this.resultsContainer.innerHTML='\n        <div class="text-center p-8 text-gray-500">\n          <p>Search is temporarily unavailable.</p>\n          <p class="text-sm mt-2">Browse the articles below instead.</p>\n        </div>\n      '}}setupSearch(){this.searchInput.addEventListener("input",e=>{clearTimeout(this.debounceTimer),this.debounceTimer=setTimeout(()=>{this.search(e.target.value.trim())},300)}),this.searchInput.addEventListener("keydown",e=>{"Enter"===e.key&&this.searchInput.value.trim()&&(e.preventDefault(),clearTimeout(this.debounceTimer),this.search(this.searchInput.value.trim()))})}search(e){if(!this.index||!this.documents)return;if(this.resultsContainer.classList.remove("hidden"),e.length<2)return void this.showHint("Type at least 2 characters to search");let t;try{t=this.index.search(e)}catch(e){return console.warn("Search query failed:",e),void this.showHint("Try a different search term")}0!==t.length?this.displayResults(t):this.showNoResults(e)}showHint(e){this.resultsContainer.innerHTML=`\n      <div class="text-center p-8 text-gray-500">\n        <p>${e}</p>\n      </div>\n    `}showNoResults(e){this.resultsContainer.innerHTML=`\n      <div class="text-center p-8">\n        <p class="text-gray-700 font-medium">No results for <span class="text-primary">"${this.escapeHtml(e)}"</span></p>\n        <p class="text-gray-500 text-sm mt-2">Try a different keyword or browse the categories.</p>\n      </div>\n    `}displayResults(e){const t=e.slice(0,10).map(e=>{const t=this.documents.find(t=>t.url===e.ref);return t?`\n        <a href="${t.url}" class="block p-4 mb-3 bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 hover:border-primary transition-colors group">\n          <div class="flex flex-col md:flex-row md:items-center gap-4">\n            <div class="flex-1">\n              <h4 class="font-display font-bold text-lg group-hover:text-primary transition-colors">${this.escapeHtml(t.title)}</h4>\n              ${t.description?`<p class="text-gray-600 dark:text-gray-400 text-sm mt-1">${this.escapeHtml(t.description)}</p>`:""}\n              <div class="flex items-center gap-3 mt-3">\n                ${t.category?`<span class="text-xs font-semibold px-2 py-1 rounded-full bg-primary/10 text-primary">${this.escapeHtml(t.category)}</span>`:""}\n                <span class="text-gray-500 text-xs">${t.date}</span>\n              </div>\n            </div>\n            <svg class="w-5 h-5 text-gray-400 group-hover:text-primary transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">\n              <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M14 5l7 7m0 0l-7 7m7-7H3"></path>\n            </svg>\n          </div>\n        </a>\n      `:""}).join("");this.resultsContainer.innerHTML=t}escapeHtml(e){const t=document.createElement("div");return t.textContent=e,t.innerHTML}}document.getElementById("search-overlay")&&document.addEventListener("DOMContentLoaded",()=>{window.workspaceSearch=new WorkspaceSearch});